import{_ as t,a,b as o,c as d,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as n,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Dropbox Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/dropbox.md","filePath":"ta/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ta/upload/dropbox.md"};function h(b,e,u,m,f,g){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="dropbox-channel-சேர்க்கவும்" tabindex="-1">Dropbox Channel சேர்க்கவும் <a class="header-anchor" href="#dropbox-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Dropbox Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="முதலில்-தேவையானவை" tabindex="-1">முதலில் தேவையானவை <a class="header-anchor" href="#முதலில்-தேவையானவை" aria-label="Permalink to &quot;முதலில் தேவையானவை&quot;">​</a></h2><table tabindex="0"><thead><tr><th>தேவை</th><th>ஏன் தேவை</th></tr></thead><tbody><tr><td>Dropbox account</td><td>sign in செய்து app authorize செய்ய</td></tr><tr><td>Dropbox app</td><td><code>App Key</code> மற்றும் <code>App Secret</code> உருவாக்க</td></tr><tr><td>உங்கள் ImgBed domain</td><td>OAuth redirect URI-க்கு</td></tr><tr><td>கிடைக்கும் Dropbox storage</td><td>உண்மையான file storage location ஆக</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-dropbox-app-உருவாக்கவும்" tabindex="-1">Step 1: Dropbox App உருவாக்கவும் <a class="header-anchor" href="#step-1-dropbox-app-உருவாக்கவும்" aria-label="Permalink to &quot;Step 1: Dropbox App உருவாக்கவும்&quot;">​</a></h3><ol><li>Dropbox App Console திறக்கவும்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>புதிய app உருவாக்கவும்.</li><li>access type-க்கு தேர்வு செய்யவும்:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>app-க்கு அறியக்கூடிய பெயர் கொடுக்கவும், உதா. <code>imgbed-app</code>.</li><li>app உருவானதும் app details page திறக்கவும்.</li></ol><p>Recommended access type:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Recommended. ImgBed files சேமிக்கும் முறைக்கு பொருந்தும்.</td></tr><tr><td><code>Full Dropbox</code></td><td>பரிந்துரை இல்லை. ImgBed-க்கு full-account access தேவையில்லை.</td></tr></tbody></table><p><img src="'+t+'" alt="Create Dropbox app" loading="lazy"></p><h3 id="step-2-redirect-uri-சேர்க்கவும்" tabindex="-1">Step 2: Redirect URI சேர்க்கவும் <a class="header-anchor" href="#step-2-redirect-uri-சேர்க்கவும்" aria-label="Permalink to &quot;Step 2: Redirect URI சேர்க்கவும்&quot;">​</a></h3><p>Dropbox app details page-ல் OAuth அல்லது Redirect URI settings-ஐ கண்டறிந்து சேர்க்கவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>admin panel-ஐ பல domains மூலம் பயன்படுத்தினால் ஒவ்வொரு matching callback URL-ஐயும் சேர்க்கவும்.</p><p><img src="'+a+'" alt="Configure redirect URI" loading="lazy"></p><h3 id="step-3-app-permissions-configure-செய்யவும்" tabindex="-1">Step 3: App Permissions Configure செய்யவும் <a class="header-anchor" href="#step-3-app-permissions-configure-செய்யவும்" aria-label="Permalink to &quot;Step 3: App Permissions Configure செய்யவும்&quot;">​</a></h3><p><code>Permissions</code> tab திறந்து குறைந்தபட்சம் இவை enable செய்யவும்:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Required</th><th>Purpose</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Required</td><td>account மற்றும் quota information படிக்கும்</td></tr><tr><td><code>files.metadata.read</code></td><td>Required</td><td>path checks-க்கு file/folder metadata படிக்கும்</td></tr><tr><td><code>files.metadata.write</code></td><td>Required</td><td>folders உருவாக்கி metadata எழுதும்</td></tr><tr><td><code>files.content.write</code></td><td>Required</td><td>files upload செய்யும். இது இல்லையெனில் <code>required scope &#39;files.content.write&#39;</code> வரும்.</td></tr><tr><td><code>files.content.read</code></td><td>Recommended</td><td>download, preview, temporary file links அனுமதிக்கும்</td></tr></tbody></table><p>scopes தேர்வு செய்த பிறகு page கீழே <code>Submit</code> கிளிக் செய்யவும்.</p><p><img src="'+o+'" alt="Add permissions" loading="lazy"></p><p>Important:</p><table tabindex="0"><thead><tr><th>Situation</th><th>What To Do</th></tr></thead><tbody><tr><td>scopes மாற்றினீர்கள்</td><td>token authorization flow மீண்டும் ஓட்டி புதிய <code>Refresh Token</code> பெறவும்.</td></tr><tr><td>reauthorize செய்யவில்லை</td><td>பழைய token-க்கு புதிய permissions கிடைக்காது; uploads இன்னும் fail ஆகலாம்.</td></tr></tbody></table><h3 id="step-4-app-credentials-copy-செய்யவும்" tabindex="-1">Step 4: App Credentials Copy செய்யவும் <a class="header-anchor" href="#step-4-app-credentials-copy-செய்யவும்" aria-label="Permalink to &quot;Step 4: App Credentials Copy செய்யவும்&quot;">​</a></h3><p>Dropbox app page-ல் இருந்து:</p><table tabindex="0"><thead><tr><th>Dropbox Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="step-5-imgbed-ல்-dropbox-channel-நிரப்பவும்" tabindex="-1">Step 5: ImgBed-ல் Dropbox Channel நிரப்பவும் <a class="header-anchor" href="#step-5-imgbed-ல்-dropbox-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 5: ImgBed-ல் Dropbox Channel நிரப்பவும்&quot;">​</a></h3><p>Upload Settings-ல் <code>Dropbox</code> தேர்வு செய்து:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>அறியக்கூடிய பெயர், உதா. <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>இப்போது காலியாக விடவும்</td></tr><tr><td>Root directory</td><td>Optional. default <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+d+'" alt="Get token" loading="lazy"></p><h3 id="step-6-refresh-token-பெறவும்" tabindex="-1">Step 6: Refresh Token பெறவும் <a class="header-anchor" href="#step-6-refresh-token-பெறவும்" aria-label="Permalink to &quot;Step 6: Refresh Token பெறவும்&quot;">​</a></h3><ol><li>ImgBed-ல் <code>Get Token</code> கிளிக் செய்யவும்.</li><li>connect செய்ய வேண்டிய Dropbox account-ல் sign in செய்யவும்.</li><li>authorization prompt approve செய்யவும்.</li><li>callback page <code>Refresh Token</code> காட்டும்.</li><li>அதை copy செய்யவும்.</li><li>ImgBed-க்கு திரும்பி <code>Refresh Token</code> field-ல் paste செய்யவும்.</li></ol><p><img src="'+r+'" alt="Copy token" loading="lazy"></p><h2 id="verify-செய்வது" tabindex="-1">Verify செய்வது <a class="header-anchor" href="#verify-செய்வது" aria-label="Permalink to &quot;Verify செய்வது&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save செய்த பிறகு Dropbox channel தெரியும்.</td></tr><tr><td>Channel switch</td><td>channel enable செய்ய முடியும்.</td></tr><tr><td>Token saved</td><td>detail page <code>Refresh Token</code> saved என காட்டும்.</td></tr><tr><td>Upload test</td><td>test image Dropbox app folder-ல் தெரியும்.</td></tr></tbody></table><p>quota limits enabled என்றால் quota query கிளிக் செய்யவும். successful query-க்கு பிறகு channel card used space, total space, last update time காட்டும்.</p><p><img src="'+p+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>ImgBed configuration incomplete என கூறும்</td><td><code>App Key</code>, <code>App Secret</code>, <code>Refresh Token</code> அனைத்தும் filled உள்ளதா பார்க்கவும்.</td></tr><tr><td>Authorization வெற்றி, ஆனால் <code>Refresh Token</code> இல்லை</td><td><code>Get Token</code> மீண்டும் கிளிக் செய்து offline authorization flow பயன்படுத்தப்படுகிறதா பார்க்கவும்.</td></tr><tr><td><code>required scope &#39;files.content.write&#39;</code> error</td><td><code>files.content.write</code> enable செய்து <code>Submit</code> கிளிக் செய்து புதிய <code>Refresh Token</code> பெறவும்.</td></tr><tr><td>Callback fail</td><td>redirect URI <code>https://your-domain.com/api/oauth/dropbox/callback</code> என confirm செய்யவும்.</td></tr><tr><td>Files கிடைக்கவில்லை</td><td>Dropbox app <code>App folder</code> mode-ல் உருவாக்கப்பட்டதா பார்க்கவும்.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Dropbox App Console திறக்கவும்</span></span>
<span class="line"><span>-&gt; app உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; App folder access தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/dropbox/callback சேர்க்கவும்</span></span>
<span class="line"><span>-&gt; account_info.read / files.metadata.read / files.metadata.write / files.content.write enable செய்யவும்</span></span>
<span class="line"><span>-&gt; optional ஆக files.content.read enable செய்யவும்</span></span>
<span class="line"><span>-&gt; Submit</span></span>
<span class="line"><span>-&gt; App Key மற்றும் App Secret copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Get Token</span></span>
<span class="line"><span>-&gt; callback page-ல் இருந்து Refresh Token copy செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-ல் paste செய்து save செய்யவும்</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const q=s(c,[["render",h]]);export{y as __pageData,q as default};
